// Banco de preguntas Verdadero/Falso — GMON32 Unidad 1 y Unidad 3
// Basado en Documento Recurso U1 (Sistemas Oleohidráulicos y Neumáticos)
// y Documento Recurso U3 (Mantenimiento de Sistemas Oleohidráulicos)
const QUESTION_BANK = [

// ============ U1 · FUNDAMENTOS ============
{id:"f001",u:1,t:"Fundamentos",q:"Si el fluido que transmite energía en un sistema hidráulico es aceite, se le denomina oleohidráulica.",a:true,e:"El texto define que cuando el sistema hidráulico usa aceite como fluido se le llama oleohidráulica."},
{id:"f002",u:1,t:"Fundamentos",q:"La hidráulica solo puede transmitir energía usando aceites minerales, ningún otro fluido es válido.",a:false,e:"También pueden emplearse líquidos sintéticos, agua o una emulsión agua-aceite."},
{id:"f003",u:1,t:"Fundamentos",q:"Una de las funciones de un sistema hidráulico es transformar la energía mecánica del motor en energía hidráulica para realizar un trabajo.",a:true,e:"Es una de las tres funciones principales descritas: transmitir fuerza, trasladar movimientos y transformar la energía."},
{id:"f004",u:1,t:"Fundamentos",q:"Los sistemas hidráulicos permiten generar movimientos lejos de la fuente de energía a bajo costo de operación.",a:true,e:"Esta es una de las ventajas descritas al trasladar movimientos."},
{id:"f005",u:1,t:"Fundamentos",q:"Entre los elementos básicos de un sistema hidráulico no se incluyen las válvulas de bloqueo.",a:false,e:"Las válvulas de bloqueo sí forman parte de los elementos básicos listados (aceite, depósito, filtro, bomba, válvulas direccionales, presión, caudal, bloqueo, actuadores, accesorios)."},
{id:"f006",u:1,t:"Fundamentos",q:"El aprendizaje esperado de la Unidad 1 de GMON32 incluye analizar el funcionamiento de circuitos oleohidráulicos y neumáticos implementados en maquinaria y vehículos pesados.",a:true,e:"Corresponde textualmente al aprendizaje esperado 1.1 de la unidad."},

// ============ U1 · ACEITE HIDRÁULICO ============
{id:"a001",u:1,t:"Aceite",q:"Una de las funciones del aceite hidráulico es sellar holguras utilizando, entre otras propiedades, la viscosidad.",a:true,e:"El documento indica que el aceite sella holguras aprovechando la propiedad de la viscosidad."},
{id:"a002",u:1,t:"Aceite",q:"El aceite hidráulico no cumple ninguna función relacionada con disipar el calor del sistema.",a:false,e:"Disipar el calor producido es una de las cinco funciones esenciales del aceite hidráulico."},
{id:"a003",u:1,t:"Aceite",q:"El aceite hidráulico debe proteger contra la corrosión y ser inocuo con los componentes del sistema.",a:true,e:"Se busca que no genere corrosión, oxidación ni ataque químicamente a los componentes."},
{id:"a004",u:1,t:"Aceite",q:"Lubricar partes móviles no es función del aceite hidráulico, solo se ocupa de transmitir potencia.",a:false,e:"Lubricar partes móviles es una de las cinco funciones básicas, junto con transmitir potencia, disipar calor, sellar holguras y proteger contra la corrosión."},
{id:"a005",u:1,t:"Aceite",q:"La película de aceite lubricante debe proteger contra el desgaste y reducir la fricción entre partes móviles.",a:true,e:"El documento lista estas funciones específicas de la lubricación de partes móviles."},
{id:"a006",u:1,t:"Aceite",q:"Según el material, la transmisión de potencia hidráulica requiere que el fluido circule con grandes pérdidas de energía por las tuberías.",a:false,e:"El fluido debe circular fácilmente con pequeñas pérdidas de energía entre la bomba y el actuador."},

// ============ U1 · DEPÓSITO ============
{id:"d001",u:1,t:"Depósito",q:"Una función principal del depósito de aceite es dar el tiempo necesario para que el aceite disipe calor y decante agua y sedimentos.",a:true,e:"El documento señala esto como la función principal del depósito, además de segregar el aire."},
{id:"d002",u:1,t:"Depósito",q:"Los depósitos de aceite hidráulico siempre deben estar abiertos a la atmósfera, nunca pueden ser cerrados y presurizados.",a:false,e:"Los depósitos pueden ser abiertos a la atmósfera o cerrados bajo presión, según el diseño."},
{id:"d003",u:1,t:"Depósito",q:"El depósito ventilado permite la compensación de presión cuando cambia el nivel de aceite.",a:true,e:"El tanque ventilado 'respira', compensando la presión al variar el nivel de aceite."},
{id:"d004",u:1,t:"Depósito",q:"Los depósitos presurizados están sellados a la atmósfera, evitando que penetre suciedad y humedad.",a:true,e:"Además, la presión interna evita la cavitación de la bomba."},
{id:"d005",u:1,t:"Depósito",q:"Entre los componentes de un depósito hidráulico típico se encuentra la plancha deflectora y el respiradero.",a:true,e:"El listado de 9 componentes del depósito incluye plancha deflectora (7) y respiradero (9), entre otros."},
{id:"d006",u:1,t:"Depósito",q:"El tubo de llenado y la mirilla no forman parte de los componentes típicos de un depósito hidráulico.",a:false,e:"El tubo de llenado (1) y la mirilla (3) sí son componentes listados del depósito."},

// ============ U1 · BOMBAS ============
{id:"b001",u:1,t:"Bombas",q:"La función de las bombas hidráulicas es convertir la energía mecánica en energía hidráulica en forma de flujo de fluido.",a:true,e:"Esta es la función central de toda bomba oleohidráulica descrita en el documento."},
{id:"b002",u:1,t:"Bombas",q:"Según el documento, las bombas generan directamente la presión del sistema.",a:false,e:"Las bombas no generan directamente la presión; esta se genera al restringir el caudal. Sin caudal no hay presión."},
{id:"b003",u:1,t:"Bombas",q:"Las bombas de engranajes externos son de caudal positivo y fijo.",a:true,e:"El documento las clasifica como bombas de caudal positivo y fijo, de diseño simple y construcción robusta."},
{id:"b004",u:1,t:"Bombas",q:"Las bombas de engranajes externos están hidráulicamente compensadas, con la misma presión en la entrada y la salida.",a:false,e:"Son descompensadas hidráulicamente: baja presión en la entrada y alta presión en la salida, lo que genera carga lateral en los ejes."},
{id:"b005",u:1,t:"Bombas",q:"Para variar el caudal de una bomba de engranajes es necesario variar la velocidad de rotación, ya que su capacidad volumétrica es constante.",a:true,e:"Su capacidad volumétrica es constante, por lo que solo variando la velocidad de giro se cambia el caudal entregado."},
{id:"b006",u:1,t:"Bombas",q:"Las placas de compensación de presión en bombas de engranajes se usan para controlar las holguras entre los engranajes y la carcasa.",a:true,e:"El aceite presurizado empuja estas placas contra los extremos de los engranajes, sellando las holguras."},
{id:"b007",u:1,t:"Bombas",q:"La bomba de engranajes internos con medialuna no posee ninguna pieza intermedia entre el piñón y la corona.",a:false,e:"Entre los piñones existe una media luna que separa los dientes del engranaje de mando y de la corona."},
{id:"b008",u:1,t:"Bombas",q:"Las bombas de paletas son bombas de larga duración y funcionamiento suave, usadas frecuentemente en maquinaria.",a:true,e:"El documento describe a las bombas de paletas con estas características."},
{id:"b009",u:1,t:"Bombas",q:"En una bomba de paletas, cuando el anillo excéntrico es fijo (carcasa fija), es posible variar el desplazamiento volumétrico.",a:false,e:"Cuando la carcasa es fija, NO se puede variar el desplazamiento volumétrico; solo se logra con carcasa móvil."},
{id:"b010",u:1,t:"Bombas",q:"En la bomba de paletas compensada, el anillo excéntrico tiene forma elíptica y las entradas y salidas opuestas compensan las fuerzas contra el rotor.",a:true,e:"La forma elíptica hace que la distancia entre rotor y anillo varíe dos veces por revolución con dos entradas y dos salidas opuestas."},
{id:"b011",u:1,t:"Bombas",q:"Las bombas de paletas usadas en equipos móviles tienen, según el documento, una presión máxima de operación de 3.500 Psi.",a:true,e:"El documento indica textualmente ese valor de presión máxima de operación para bombas de paletas en equipos móviles."},
{id:"b012",u:1,t:"Bombas",q:"Las bombas de paletas de caudal variable normalmente se usan en sistemas móviles, nunca en sistemas estacionarios.",a:false,e:"Es al revés: este tipo de bombas normalmente se ocupa en sistemas estacionarios."},
{id:"b013",u:1,t:"Bombas",q:"Las bombas de pistones pueden ser de caudal fijo o variable según su diseño.",a:true,e:"El documento lo indica explícitamente para las bombas de pistones axiales."},
{id:"b014",u:1,t:"Bombas",q:"En una bomba de pistones axiales de placa inclinada, si la placa queda sin inclinación, el caudal de la bomba es nulo.",a:true,e:"Sin inclinación de la placa no hay desplazamiento de los pistones y por tanto el caudal entregado es cero."},
{id:"b015",u:1,t:"Bombas",q:"En la bomba de pistones de cabezal inclinado, a mayor ángulo de la carcasa, menor es el desplazamiento por revolución.",a:false,e:"Es al revés: a mayor ángulo de la carcasa, mayor es el desplazamiento por cada revolución de la bomba."},
{id:"b016",u:1,t:"Bombas",q:"El flujo de salida de una bomba de pistones de caudal fijo solo se puede modificar cambiando la velocidad del eje de salida.",a:true,e:"Al ser de caudal fijo, la única forma de variar el flujo es cambiando la velocidad del eje."},
{id:"b017",u:1,t:"Bombas",q:"En la bomba de pistones axiales de placa inclinada (plato basculante), la velocidad del eje se mantiene constante mientras varía el ángulo de la placa.",a:true,e:"El pistón pivota cambiando el ángulo respecto al eje, variando el flujo entre máximos y mínimos con velocidad de eje constante."},
{id:"b018",u:1,t:"Bombas",q:"Normalmente las bombas de pistones tienen un número par de pistones para equilibrar mejor las fuerzas.",a:false,e:"Normalmente las bombas de pistones son de número impar de pistones (esto ayuda a suavizar el pulso de caudal entregado)."},
{id:"b019",u:1,t:"Bombas",q:"Entre los términos comunes para clasificar bombas oleohidráulicas están: caudal positivo, caudal fijo, caudal variable, presión compensada y doble dirección.",a:true,e:"Estos cinco términos son mencionados textualmente en el documento como clasificación de bombas."},
{id:"b020",u:1,t:"Bombas",q:"Según el documento, las bombas de engranajes externos tienen una presión nominal de hasta 300 bar.",a:true,e:"El documento indica textualmente este valor como una de las características de las bombas de engranajes externos."},

// ============ U1 · VÁLVULAS ============
{id:"v001",u:1,t:"Válvulas",q:"Las válvulas hidráulicas se agrupan generalmente en 4 categorías: control direccional, control de flujo, control de presión y de bloqueo.",a:true,e:"El documento agrupa las válvulas hidráulicas en exactamente estas 4 categorías."},
{id:"v002",u:1,t:"Válvulas",q:"Las válvulas de control direccional solo pueden ser accionadas manualmente, nunca con mandos eléctricos o neumáticos.",a:false,e:"Pueden ser accionadas con controles manuales, hidráulicos, neumáticos y electrónicos, según el equipo."},
{id:"v003",u:1,t:"Válvulas",q:"Las válvulas de control de presión se agrupan en 3 categorías: alivio, secuencia y reductoras de presión.",a:true,e:"El documento lo confirma textualmente, mencionando también sus nombres alternativos (seguridad, limitadora, reguladora, relief)."},
{id:"v004",u:1,t:"Válvulas",q:"Cuando la presión de un sistema sobrepasa un nivel predeterminado, la válvula de alivio se abre y descarga el aceite a tanque.",a:true,e:"Esta es la función de protección característica de la válvula de alivio de presión."},
{id:"v005",u:1,t:"Válvulas",q:"Las válvulas de secuencia se conectan al ducto de descarga T al igual que la válvula de alivio.",a:false,e:"A diferencia de la válvula de alivio, la de secuencia no se conecta a T sino a un ducto A de trabajo."},
{id:"v006",u:1,t:"Válvulas",q:"Las válvulas de secuencia se utilizan para alimentar o conectar un circuito secundario cuando la presión del sistema alcanza un valor preestablecido.",a:true,e:"Esta es la definición exacta de la función de las válvulas de secuencia."},
{id:"v007",u:1,t:"Válvulas",q:"La válvula limitadora de presión de mando directo por carga es amortiguada hidráulicamente.",a:false,e:"Es la válvula de mando indirecto por descarga la que es amortiguada hidráulicamente; la de mando directo por carga no es amortiguada y tiene un comportamiento brusco."},
{id:"v008",u:1,t:"Válvulas",q:"La válvula de presión de mando indirecto por descarga enfrenta fuerza hidráulica contra fuerza hidráulica, dando un comportamiento suave.",a:true,e:"Esto contrasta con el mando directo por carga, que es fuerza hidráulica versus fuerza mecánica (resorte), de comportamiento brusco."},
{id:"v009",u:1,t:"Válvulas",q:"Las válvulas reductoras de presión se usan cuando la demanda de presión de un circuito secundario es mayor que la presión de suministro.",a:false,e:"Se usan cuando la demanda de presión del circuito secundario es MENOR que la presión de la línea principal."},
{id:"v010",u:1,t:"Válvulas",q:"En la válvula reductora de presión, si la presión de línea aumenta, la válvula se desconecta impidiendo el paso de más aceite.",a:true,e:"Así mantiene controlada la presión de salida de la válvula reductora."},
{id:"v011",u:1,t:"Válvulas",q:"Cuando una válvula de control de flujo solo controla la sección de paso del fluido, se le llama estranguladora de caudal.",a:true,e:"El documento define así a las válvulas que solo restringen la sección de paso, sin compensar presión."},
{id:"v012",u:1,t:"Válvulas",q:"Una válvula de caudal que deriva el fluido sobrante en la línea se denomina reguladora de presión o válvula de caudal compensada respecto a la presión.",a:true,e:"Esta es la definición exacta que entrega el documento para este tipo de válvula de control de flujo."},
{id:"v013",u:1,t:"Válvulas",q:"El diseño más común de una válvula de retención o bloqueo consiste en un pistón o bola junto a un resorte.",a:true,e:"El documento describe este diseño típico para las válvulas de retención."},
{id:"v014",u:1,t:"Válvulas",q:"La válvula unidireccional de pistón hueco y muelle permite el paso de flujo en ambos sentidos por igual.",a:false,e:"Deja pasar el flujo solo en un sentido (de P hacia A), impidiendo el paso en sentido contrario (de A a P)."},
{id:"v015",u:1,t:"Válvulas",q:"En una válvula distribuidora 4/3 de centro tándem, en posición central el aceite proveniente de la bomba retorna directamente al depósito.",a:true,e:"En el centro tándem con derivación a depósito, el aceite entra por P y sale por T en la posición neutra."},
{id:"v016",u:1,t:"Válvulas",q:"Al accionar la palanca de una válvula 4/3 de centro tándem hacia un lado, el aceite se dirige de P a B y retorna de A a T.",a:true,e:"Así lo describe el análisis de funcionamiento de la válvula distribuidora 4/3 centro tándem."},
{id:"v017",u:1,t:"Válvulas",q:"Las válvulas de control de flujo se utilizan únicamente para dividir el flujo entre circuitos, nunca para regular la velocidad de actuadores.",a:false,e:"Se utilizan tanto para regular la velocidad de los actuadores como para dividir el flujo entre dos o más circuitos."},

// ============ U1 · ACTUADORES Y ACUMULADORES ============
{id:"ac001",u:1,t:"Actuadores",q:"El motor oleohidráulico convierte la energía oleohidráulica en energía mecánica, generando un movimiento rotatorio.",a:true,e:"Esta es la función descrita para los actuadores rotatorios (motores oleohidráulicos)."},
{id:"ac002",u:1,t:"Actuadores",q:"Los cilindros oleohidráulicos son actuadores rotatorios que convierten energía mecánica en energía hidráulica.",a:false,e:"Los cilindros son actuadores LINEALES que convierten energía HIDRÁULICA en energía MECÁNICA (lo contrario de lo afirmado)."},
{id:"ac003",u:1,t:"Actuadores",q:"Entre los componentes de un cilindro de doble efecto se cuentan el vástago, el pistón y la cabeza del cilindro.",a:true,e:"Estos son parte de los 8 componentes listados de un cilindro de doble efecto."},
{id:"ac004",u:1,t:"Actuadores",q:"Un cilindro hidráulico de doble efecto típico solo posee un tipo de sello en todo su recorrido.",a:false,e:"El documento describe varios tipos de sellos: limpiador, amortiguador del vástago, del pistón, de la cabeza, anillos de desgaste, etc."},
{id:"ac005",u:1,t:"Acumuladores",q:"Existen 3 tipos básicos de acumuladores oleohidráulicos: contrapesado, de resorte y cargado con gas.",a:true,e:"El documento enumera exactamente estos tres tipos básicos de acumuladores."},
{id:"ac006",u:1,t:"Acumuladores",q:"Los acumuladores oleohidráulicos son recipientes que almacenan el aceite a presión.",a:true,e:"Esta es la función principal descrita para los acumuladores."},

// ============ U1 · FILTROS, ENFRIADORES, TUBERÍAS ============
{id:"fi001",u:1,t:"Filtros",q:"Los filtros oleohidráulicos retienen los contaminantes que pueden dañar los componentes del sistema.",a:true,e:"El aceite pasa por el elemento filtrante quedando atrapados los contaminantes, y el aceite limpio continúa por el sistema."},
{id:"fi002",u:1,t:"Filtros",q:"La válvula de derivación de un filtro se abre cuando la presión antes del filtro disminuye demasiado.",a:false,e:"Se abre cuando la presión AUMENTA (filtro obturado), venciendo la tensión del resorte y permitiendo que el aceite se desvíe sin filtrar."},
{id:"fi003",u:1,t:"Filtros",q:"El aceite que pasa por la válvula de derivación de un filtro obturado queda sin filtrar.",a:true,e:"El aceite derivado no está filtrado, por lo cual se debe dar servicio al filtro lo antes posible."},
{id:"en001",u:1,t:"Enfriadores",q:"Se usan dos tipos de enfriadores hidráulicos en equipo móvil: por aire a aceite y por agua a aceite.",a:true,e:"El documento describe estos dos tipos: intercambiador por aire (tubos con aletas) y por agua (tubos y coraza)."},
{id:"en002",u:1,t:"Enfriadores",q:"El enfriador de aceite hidráulico funciona de forma similar al radiador de un automóvil.",a:true,e:"El documento compara explícitamente los enfriadores de aceite con el radiador de un vehículo."},
{id:"tu001",u:1,t:"Tuberías",q:"Las tuberías rígidas se utilizan para conectar componentes que no rozan entre sí y requieren menos espacio.",a:true,e:"Así se describen las tuberías rígidas, generalmente de acero, en el documento."},
{id:"tu002",u:1,t:"Tuberías",q:"Las mangueras hidráulicas se utilizan cuando se necesita flexibilidad, por ejemplo cuando hay movimiento relativo entre componentes.",a:true,e:"Las mangueras absorben vibraciones y resisten variaciones de presión en esos casos."},
{id:"tu003",u:1,t:"Tuberías",q:"Las conexiones y acoples se usan para interconectar mangueras y tubos a los componentes hidráulicos.",a:true,e:"Esta es la función descrita para las conexiones, bridas y conectores del sistema."},

// ============ U1 · SIMBOLOGÍA ISO 1219 ============
{id:"si001",u:1,t:"Simbología",q:"Según la norma ISO 1219, el símbolo básico que representa a una bomba o motor hidráulico es un círculo.",a:true,e:"El documento indica que el círculo es el símbolo básico de bombas y motores hidráulicos."},
{id:"si002",u:1,t:"Simbología",q:"En la simbología ISO, se pueden añadir triángulos al símbolo básico de una bomba para indicar la dirección del flujo o de la energía.",a:true,e:"Los triángulos indican la dirección del fluido o del flujo de energía en el símbolo de la bomba."},
{id:"si003",u:1,t:"Simbología",q:"El símbolo básico ISO que representa una válvula es un círculo, igual que el de las bombas.",a:false,e:"El símbolo básico de una válvula es un cuadrado o recuadro, distinto del círculo usado para bombas y motores."},
{id:"si004",u:1,t:"Simbología",q:"En los símbolos ISO de válvulas, la cantidad de recuadros representa la cantidad de posiciones de la válvula.",a:true,e:"Las válvulas de control direccional aparecen como recuadros múltiples según su número de posiciones."},
{id:"si005",u:1,t:"Simbología",q:"En la simbología ISO, la designación T en una válvula significa tanque, P significa presión, y A y B son lumbreras de trabajo.",a:true,e:"Esta es la nomenclatura estándar de designación de líneas y conexiones de válvulas."},
{id:"si006",u:1,t:"Simbología",q:"Una válvula 4/3 significa que tiene 4 posiciones de detención y 3 conexiones.",a:false,e:"Es al revés: en la notación X/Y, el primer número son las conexiones y el segundo las posiciones. Una 4/3 tiene 4 conexiones y 3 posiciones."},
{id:"si007",u:1,t:"Simbología",q:"El símbolo ISO de una válvula de centro cerrado muestra que, en posición neutral, las cuatro lumbreras quedan cerradas.",a:true,e:"Así se describe el comportamiento de la válvula direccional de centro cerrado en posición neutral."},
{id:"si008",u:1,t:"Simbología",q:"Las líneas paralelas dibujadas junto al símbolo de una válvula representan la posibilidad de infinitas posiciones intermedias (proporcional).",a:true,e:"Estas dos líneas paralelas indican que la válvula puede tomar posiciones intermedias, no solo las extremas."},
{id:"si009",u:1,t:"Simbología",q:"El símbolo básico de un cilindro hidráulico es un rectángulo con una representación en T del pistón y la varilla.",a:true,e:"El rectángulo representa el tubo del cilindro y la forma de T al pistón y vástago."},
{id:"si010",u:1,t:"Simbología",q:"Un cilindro de simple efecto se representa con dos lumbreras cerradas en sus extremos.",a:false,e:"El cilindro de simple efecto muestra una lumbrera única, dejando la otra abierta para indicar descarga; las dos lumbreras cerradas corresponden al de doble efecto."},
{id:"si011",u:1,t:"Simbología",q:"En un cilindro telescópico de doble efecto, el símbolo muestra dos lumbreras y los extremos de las varillas cerrados.",a:true,e:"Así se diferencia del telescópico de simple efecto, que tiene una sola lumbrera y varillas de extremo abierto."},
{id:"si012",u:1,t:"Simbología",q:"El amortiguador de un cilindro se representa mediante un círculo grande al centro del pistón.",a:false,e:"Se representa mediante un rectángulo pequeño a un lado o ambos lados del pistón, no un círculo."},
{id:"si013",u:1,t:"Simbología",q:"El símbolo ISO de un depósito hidráulico ventilado es un rectángulo abierto con una tubería de retorno.",a:true,e:"Los tanques presurizados, en cambio, se representan como un rectángulo cerrado."},
{id:"si014",u:1,t:"Simbología",q:"El símbolo básico de un acumulador puede modificarse internamente para indicar si es con resorte, cargado con gas o contrapesado.",a:true,e:"El símbolo básico admite variantes internas para diferenciar los tres tipos de acumulador."},
{id:"si015",u:1,t:"Simbología",q:"El símbolo ISO de un manómetro es distinto al de un termómetro dentro de un circuito hidráulico.",a:true,e:"Ambos instrumentos tienen símbolos ISO diferenciados: uno para manómetro y otro para termómetro."},
{id:"si016",u:1,t:"Simbología",q:"En un esquema hidráulico real, las letras P y T identifican habitualmente la línea de presión y la línea de tanque o retorno respectivamente.",a:true,e:"Esta nomenclatura P (presión) y T (tanque/retorno) es estándar en simbología ISO y se observa en planos hidráulicos reales de equipos."},
{id:"si017",u:1,t:"Simbología",q:"La sigla LS en un esquema hidráulico corresponde a Load Sensing (detección de carga).",a:true,e:"LS es la abreviatura estándar de la industria para los sistemas de detección de carga (Load Sensing)."},
{id:"si018",u:1,t:"Simbología",q:"Un plano hidráulico tipo cutaway y un plano esquemático muestran exactamente la misma información sin ninguna diferencia.",a:false,e:"El cutaway es un dibujo en corte que muestra la construcción interna del componente, mientras que el esquemático usa símbolos geométricos simples para mostrar componentes, controles y conexiones."},

// ============ U1 · ANÁLISIS DE CIRCUITOS ============
{id:"ci001",u:1,t:"Circuitos",q:"En el circuito con cilindro de doble efecto y válvula 4/3 centro tándem, en posición central el aceite de la bomba retorna directo al depósito.",a:true,e:"Así se describe el comportamiento del sistema en la posición de reposo (centro tándem) de la válvula 4/3."},
{id:"ci002",u1:1,u:1,t:"Circuitos",q:"En posición de flechas paralelas del circuito con cilindro, el fluido se desplaza del ducto P hacia A logrando la salida del émbolo.",a:true,e:"Esta es la descripción exacta del análisis de funcionamiento para la carrera de avance del cilindro."},
{id:"ci003",u:1,t:"Circuitos",q:"En posición de flechas cruzadas, la válvula de bloqueo con pilotaje impide inicialmente el retorno hasta que la presión piloteé su apertura.",a:true,e:"Se describe que al aumentar la presión en la línea se pilotea la señal X de la válvula de bloqueo, permitiendo la entrada del vástago."},
{id:"ci004",u:1,t:"Circuitos",q:"En el circuito con motor oleohidráulico de doble sentido de giro, la válvula de control de inercia actúa solo cuando la válvula 4/3 está en posición de flechas paralelas.",a:false,e:"La válvula de control de inercia actúa cuando la válvula 4/3 es desactivada o llevada a la posición central, cerrando las lumbreras A y B."},
{id:"ci005",u:1,t:"Circuitos",q:"En un circuito neumático con cilindro de simple efecto y válvula 3/2, el mando indirecto usa una válvula 3/2 monoestable que controla a otra válvula 3/2 de mando neumático.",a:true,e:"Así describe el documento el mando indirecto del cilindro de simple efecto en el circuito neumático básico."},
{id:"ci006",u:1,t:"Circuitos",q:"En el circuito neumático con cilindro de doble efecto controlado por válvula 5/2 biestable con dos rodillos (A0 y A1), el rodillo A0 controla el retorno del vástago y A1 el avance.",a:false,e:"Es al revés: A0 controla el avance del vástago y A1 controla el retorno de este."},
{id:"ci007",u:1,t:"Circuitos",q:"El análisis de funcionamiento de circuitos es un paso previo al montaje del circuito en maquinaria o banco de entrenamiento.",a:true,e:"El documento indica que este análisis se realiza antes del montaje, con el fin de simular su óptimo funcionamiento."},
{id:"ci008",u:1,t:"Circuitos",q:"Es riesgoso intervenir un sistema hidráulico sin revisar previamente su plano hidráulico y sin conocer su funcionamiento.",a:true,e:"El documento advierte explícitamente sobre este riesgo antes de intervenir un sistema."},
{id:"ci009",u:1,t:"Circuitos",q:"El uso de planos hidráulicos ayuda en el armado del circuito, el diagnóstico y el análisis de fallas del sistema.",a:true,e:"Estas son varias de las utilidades descritas para el uso de planos hidráulicos en mantenimiento."},

// ============ U3 · INSUMOS, REPUESTOS, HERRAMIENTAS ============
{id:"in001",u:3,t:"Insumos",q:"Los insumos son la materia prima utilizada para producir o mantener elementos, dependiendo del rubro donde se aplican.",a:true,e:"Esta es la definición exacta de insumos dada en el Documento Recurso 3."},
{id:"in002",u:3,t:"Insumos",q:"Un repuesto es cualquier instrumento que se utiliza para facilitar una actividad mecánica.",a:false,e:"Esa es la definición de herramienta. El repuesto es la parte o pieza de un sistema, sustituible por otra igual o que cumple la misma función."},
{id:"in003",u:3,t:"Insumos",q:"Para el cambio de aceite y filtro de un sistema hidráulico, el elemento filtrante y el aceite hidráulico se clasifican como repuestos.",a:true,e:"El ejemplo del D6T de Caterpillar clasifica el elemento filtrante y el aceite como repuestos, distinto de insumos y herramientas."},
{id:"in004",u:3,t:"Insumos",q:"El contenedor de aceite usado y la llave para filtro se clasifican en el ejemplo como herramientas necesarias para el cambio de aceite.",a:true,e:"El documento las agrupa dentro de las herramientas requeridas para el procedimiento, junto con la caja de herramientas y el equipo de trasvasije."},

// ============ U3 · CAMBIO DE ACEITE ============
{id:"ca001",u:3,t:"Cambio de aceite",q:"El intervalo normal de cambio de aceite hidráulico es cada 2000 horas de servicio o cada un año.",a:true,e:"Este es el intervalo normal indicado en el documento, aunque en ciertos casos puede extenderse hasta 4000 horas."},
{id:"ca002",u:3,t:"Cambio de aceite",q:"El intervalo de cambio de aceite puede extenderse hasta 4000 horas si se realizan pruebas de aceite cada 500 horas y estas indican buenas condiciones.",a:true,e:"El documento indica que prolongar el intervalo de 2000 a 4000 horas solo se recomienda si el muestreo periódico confirma que el aceite está en buen estado."},
{id:"ca003",u:3,t:"Cambio de aceite",q:"Las máquinas que operan en condiciones extremas son las más recomendadas para extender el cambio de aceite a 4000 horas.",a:false,e:"Es al contrario: en condiciones extremas de operación NO se recomienda extender a 4000 horas, se sugiere mantener el cambio cada 2000 horas o un año."},
{id:"ca004",u:3,t:"Cambio de aceite",q:"Para los sistemas hidráulicos de máquinas Caterpillar se recomienda usar aceites hidráulicos industriales genéricos en lugar de los aprobados por el fabricante.",a:false,e:"El documento advierte que no se recomienda el uso de aceites hidráulicos industriales en máquinas Caterpillar, ya que son más propensos a permitir corrosión y desgaste excesivo."},
{id:"ca005",u:3,t:"Cambio de aceite",q:"Los aceites comerciales para motores Diesel de servicio pesado aceptables para uso hidráulico deben tener un contenido mínimo de zinc de 900 ppm.",a:true,e:"El documento especifica este valor mínimo de contenido de zinc según la clasificación API (FC, CF-4, CG-4, CH-4)."},
{id:"ca006",u:3,t:"Cambio de aceite",q:"Antes de retirar la tapa de llenado del depósito hidráulico, se debe hacerlo rápidamente para ahorrar tiempo, sin importar la temperatura de la tapa.",a:false,e:"Debe quitarse solo con la máquina detenida, el motor parado y la tapa fría al contacto con la mano, retirándola lentamente para aliviar la presión."},
{id:"ca007",u:3,t:"Cambio de aceite",q:"Antes de cambiar el aceite se recomienda operar la máquina para calentarlo, estacionarla en un lugar horizontal y bajar la hoja o el desgarrador al piso.",a:true,e:"Estos son pasos previos indicados en la gama operacional para el cambio de aceite del sistema oleohidráulico."},

// ============ U3 · SEGURIDAD Y EPP ============
{id:"se001",u:3,t:"Seguridad",q:"Si una etiqueta de advertencia en la máquina se daña o falta, se debe reemplazar de inmediato por una nueva.",a:true,e:"El documento indica que las etiquetas dañadas o faltantes deben reemplazarse inmediatamente."},
{id:"se002",u:3,t:"Seguridad",q:"Para limpiar etiquetas de advertencia sucias se recomienda usar disolventes o gasolina para asegurar una limpieza profunda.",a:false,e:"Nunca se deben usar disolventes, gasolinas u otros productos químicos, ya que pueden borrar las etiquetas o dañar el pegamento. Se recomiendan paños secos o húmedos."},
{id:"se003",u:3,t:"Seguridad",q:"Antes de intervenir una máquina, siempre es necesario colocar una etiqueta de 'Do Not Operate' en el interruptor de arranque.",a:true,e:"Esta es una recomendación explícita para evitar el funcionamiento del equipo mientras se realiza servicio o reparación."},
{id:"se004",u:3,t:"Seguridad",q:"Los elementos de protección personal (EPP) mencionados en el documento incluyen zapatos de seguridad, guantes, gafas y protectores de oído.",a:true,e:"Estos EPP están explícitamente listados para el mantenimiento de sistemas oleohidráulicos y neumáticos."},
{id:"se005",u:3,t:"Seguridad",q:"Entre las recomendaciones generales de seguridad está el permitir fumar cerca de la maquinaria mientras se hace mantenimiento.",a:false,e:"Una de las recomendaciones generales explícitas es justamente 'no fumar' durante el proceso."},
{id:"se006",u:3,t:"Seguridad",q:"Nunca se debe poner aceite en recipientes de vidrio según las recomendaciones generales del documento.",a:true,e:"Esta es una de las recomendaciones generales de seguridad listadas explícitamente."},
{id:"se007",u:3,t:"Seguridad",q:"La presión máxima de aire para propósitos de limpieza debe reducirse a un máximo de 205 kPa (30 psi) usando un deflector eficaz y equipo de protección.",a:true,e:"El documento especifica este valor máximo de presión de aire para limpieza con boquilla y deflector."},
{id:"se008",u:3,t:"Seguridad",q:"La presión máxima de agua para fines de limpieza según el documento debe ser inferior a 275 kPa (40 psi).",a:true,e:"Este es el valor límite indicado explícitamente en el documento para el uso de agua a presión en limpieza."},
{id:"se009",u:3,t:"Seguridad",q:"Puede quedar presión atrapada en un sistema hidráulico incluso después de haber parado el motor de la máquina.",a:true,e:"El documento advierte que la presión atrapada puede persistir bastante después de detener el motor, representando riesgo al intervenir el equipo."},
{id:"se010",u:3,t:"Seguridad",q:"Para comprobar si hay fugas de aceite se recomienda deslizar la mano directamente sobre la línea hidráulica para sentir la fuga.",a:false,e:"Nunca se deben usar las manos desprotegidas; se recomienda usar una tabla o cartón para comprobar fugas, debido al riesgo de inyección de fluido a alta presión."},
{id:"se011",u:3,t:"Seguridad",q:"Una fuga del tamaño del agujero de un alfiler no representa riesgo real de lesión para una persona.",a:false,e:"El documento advierte que incluso una fuga del tamaño de un alfiler puede ocasionar lesiones graves por inyección de fluido a presión."},
{id:"se012",u:3,t:"Seguridad",q:"Si el fluido hidráulico se inyecta en la piel a alta presión, se debe buscar tratamiento médico especializado de inmediato.",a:true,e:"El documento enfatiza la urgencia de atención médica especializada ante este tipo de lesión."},
{id:"se013",u:3,t:"Seguridad",q:"Un sistema hidráulico común trabaja habitualmente entre 2000 y 3000 psi, aunque algunos sistemas más sofisticados pueden operar hasta 10.000 psi.",a:true,e:"Estos rangos de presión de operación están indicados explícitamente en la sección de riesgos del documento."},
{id:"se014",u:3,t:"Seguridad",q:"Según el documento, una fuga de manguera hidráulica bajo presión puede liberar fluido a una velocidad cercana a la de la boca de un arma de fuego (185 m/s).",a:true,e:"El documento compara esta velocidad de fuga con la de un proyectil, resaltando el peligro de la inyección de fluido."},
{id:"se015",u:3,t:"Seguridad",q:"Con presiones superiores a 7000 psi, la probabilidad de amputación por inyección de aceite en la piel es del 100%.",a:true,e:"El documento presenta esta tabla de consecuencias según el nivel de presión de inyección."},
{id:"se016",u:3,t:"Seguridad",q:"Con presiones menores a 2000 psi no existe ningún riesgo de amputación por inyección de fluido.",a:false,e:"Incluso a menos de 2000 psi el documento indica un 40% de probabilidades de amputación."},
{id:"se017",u:3,t:"Seguridad",q:"El trabajador expuesto a sistemas oleohidráulicos enfrenta 3 tipos de riesgos: quemaduras, inyección de aceite a presión, y contusiones o cortes.",a:true,e:"Estos son los tres tipos de riesgos descritos textualmente en el documento."},
{id:"se018",u:3,t:"Seguridad",q:"Los acumuladores hidráulicos garantizan que el sistema nunca estará bajo presión una vez que la bomba se detiene o se apaga el motor.",a:false,e:"Es al revés: los acumuladores están diseñados para mantener el aceite bajo presión incluso con la bomba detenida o el motor apagado, por lo que el sistema puede seguir presurizado."},
{id:"se019",u:3,t:"Seguridad",q:"Se recomienda cambiar mangueras hidráulicas si presentan capas exteriores hinchadas o cables de refuerzo expuestos.",a:true,e:"Estas son condiciones explícitas indicadas para el reemplazo de mangueras, tubos y tuberías."},
{id:"se020",u:3,t:"Seguridad",q:"Está permitido instalar una tubería doblada en un sistema hidráulico siempre que no presente fugas visibles.",a:false,e:"El documento indica explícitamente nunca instalar una tubería que esté doblada o dañada en un sistema hidráulico."},

// ============ U3 · DERRAMES Y RESIDUOS ============
{id:"re001",u:3,t:"Ambiental",q:"Ante un cambio de aceite u otra intervención, se debe estar preparado para recoger el fluido en recipientes adecuados.",a:true,e:"Esta es una recomendación explícita para contener derrames durante mantenimiento e inspecciones."},
{id:"re002",u:3,t:"Ambiental",q:"Es aceptable verter los desechos de aceite hidráulico directamente al suelo si la cantidad es pequeña.",a:false,e:"El documento indica no verter los desechos sobre el suelo, drenaje ni ninguna fuente de agua, sin excepciones por cantidad."},
{id:"re003",u:3,t:"Ambiental",q:"El derrame de aceite hidráulico puede contaminar miles de litros de agua si llega a ductos o napas subterráneas.",a:true,e:"El documento explica el problema ambiental del aceite hidráulico derramado en fuentes de agua."},
{id:"re004",u:3,t:"Ambiental",q:"En Chile, la ley N°20.920 (ley REP) regula, entre otros productos, los aceites lubricantes, baterías y neumáticos.",a:true,e:"La ley REP (responsabilidad extendida del productor) regula estos productos prioritarios según el documento."},
{id:"re005",u:3,t:"Ambiental",q:"La ley REP propone alcanzar al año 2030 una recolección del 90% de los aceites lubricantes usados.",a:true,e:"Este es el porcentaje objetivo mencionado explícitamente en el documento para el año 2030."},
{id:"re006",u:3,t:"Ambiental",q:"Actualmente, según el documento, más del 80% de los aceites usados en Chile son reciclados correctamente.",a:false,e:"El documento indica que hoy en día un poco menos del 50% de los aceites usados son reciclados; el resto tiene destino desconocido."},
{id:"re007",u:3,t:"Ambiental",q:"El principio de la ley REP se resume en la frase 'el que contamina paga'.",a:true,e:"Así se describe explícitamente el principio de la responsabilidad extendida del producto en el documento."},

// ============ U3 · PROCEDIMIENTOS DE MANTENIMIENTO ============
{id:"ma001",u:3,t:"Mantenimiento",q:"Todo procedimiento de mantenimiento realizado a un equipo debe quedar registrado en su hoja de vida.",a:true,e:"El documento indica que cada procedimiento realizado al equipo debe ser registrado en su hoja de vida."},
{id:"ma002",u:3,t:"Mantenimiento",q:"Los mantenimientos preventivos o programados se realizan únicamente según el calendario, sin relación con las horas de trabajo del equipo.",a:false,e:"Se realizan de acuerdo con el número de horas de trabajo de los equipos, y en otros casos según el kilometraje de operación."},
{id:"ma003",u:3,t:"Mantenimiento",q:"Un informe de mantenimiento debe contener el nombre de la actividad, su descripción, el responsable y el registro de la actividad.",a:true,e:"Estos cuatro elementos son los que debe contener el informe según el documento."},
{id:"ma004",u:3,t:"Mantenimiento",q:"Entre los tipos de procedimientos de mantenimiento de sistemas hidráulicos se incluyen el cambio de aceite, el cambio de filtros y la calibración de instrumentos.",a:true,e:"Estos tres, junto con cambio de mangueras, inspecciones, verificación de presiones/caudales, reparación y sustitución de componentes, son los tipos listados."},
{id:"ma005",u:3,t:"Mantenimiento",q:"Para realizar un cambio de filtro es útil contar con la ficha técnica de la máquina y del filtro, además del manual de procedimiento.",a:true,e:"Estos documentos se mencionan como material adicional requerido para el proceso de cambio de filtro."},

// ============ U3 · VERIFICACIÓN DE FUNCIONAMIENTO ============
{id:"ve001",u:3,t:"Verificación",q:"Las listas de verificación de funcionamiento de un sistema hidráulico están normadas exclusivamente por el operador de la máquina, sin relación con el fabricante.",a:false,e:"Están normadas por el fabricante de la maquinaria, aunque también existen pautas adicionales de las empresas (políticas del taller)."},
{id:"ve002",u:3,t:"Verificación",q:"Las verificaciones periódicas de un sistema oleohidráulico consisten en acciones de verificar, probar, ajustar y reemplazar.",a:true,e:"Estas cuatro acciones conforman el listado de observaciones sobre el sistema que se realiza en las verificaciones periódicas."},
{id:"ve003",u:3,t:"Verificación",q:"En el ejemplo del camión Komatsu 930E, el paso 6 del ajuste de control de presión de la bomba busca obtener 22.925 kPa en el indicador de presión de la lumbrera GPA.",a:true,e:"Este es el valor exacto indicado en el ejemplo de procedimiento de revisión del camión 930E."},
{id:"ve004",u:3,t:"Verificación",q:"En el sistema de dirección del camión 930E, los acumuladores de la dirección se cargan a 9650 kPa (1400 psi) según el documento.",a:true,e:"Este es el valor de carga indicado en la hoja de datos del sistema de dirección del 930E."},

// ============ U3 · BLOQUEO, DETENCIÓN Y PUESTA EN MARCHA ============
{id:"bl001",u:3,t:"Bloqueo",q:"Uno de los primeros pasos de un protocolo de detención es comunicar a todos los involucrados que se realizará control de rutina, mantenimiento o reparación.",a:true,e:"El documento indica esto como el primer paso del protocolo de detención de la maquinaria."},
{id:"bl002",u:3,t:"Bloqueo",q:"Al aislar las energías del sistema, los acumuladores hidráulicos deben bloquearse o descargarse antes de intervenir el equipo.",a:true,e:"El documento indica que los acumuladores de energía deben bloquearse o descargarse antes de intervenir el sistema."},
{id:"bl003",u:3,t:"Bloqueo",q:"No es necesario rotular un equipo en mantenimiento si ya se aislaron sus fuentes de energía.",a:false,e:"Aun aislando las energías, es necesario rotular claramente que el equipo no puede ponerse en funcionamiento ni maniobrarse durante el proceso."},
{id:"bl004",u:3,t:"Bloqueo",q:"El candado Safekey utiliza una llave electrónica única por candado, brindando alta seguridad al bloqueo de maquinaria.",a:true,e:"El documento describe el Safekey como un candado con llave electrónica única de alta seguridad."},
{id:"bl005",u:3,t:"Bloqueo",q:"El cerrojo de bloqueo se instala sobre componentes móviles de la maquinaria para evitar su movimiento durante el mantenimiento.",a:true,e:"Esta es la función descrita para el cerrojo de bloqueo entre los elementos de bloqueo de maquinaria."},
{id:"bl006",u:3,t:"Bloqueo",q:"Las cajas para bloqueo general se utilizan para encerrar las llaves de equipos en mantenimiento hasta que el último mantenedor se retire.",a:true,e:"Esta es la función descrita para las cajas de bloqueo general en el procedimiento de bloqueo."},
{id:"bl007",u:3,t:"Bloqueo",q:"El dispositivo para bloqueo de válvulas se utiliza para bloquear o deshabilitar válvulas en sistemas hidráulicos, normalmente con etiquetas explicativas.",a:true,e:"Así se describe este dispositivo específico de bloqueo dentro de los elementos de bloqueo de maquinaria."},
{id:"bl008",u:3,t:"Bloqueo",q:"Las bolsas para bloqueo se usan para bloquear grupos de mando de controladores manuales de la maquinaria.",a:true,e:"Esta es la función descrita para las bolsas de bloqueo en el documento."},
{id:"bl009",u:3,t:"Bloqueo",q:"Después de un mantenimiento, la maquinaria puede ponerse en marcha sin retirar los dispositivos de bloqueo, ya que estos no afectan el arranque.",a:false,e:"Antes de poner en marcha se debe retirar las herramientas, cerrar los compartimientos y proceder al retiro de los dispositivos de bloqueo."},
{id:"bl010",u:3,t:"Bloqueo",q:"Antes de poner en marcha el equipo tras el mantenimiento, se debe verificar que no haya nadie alrededor del equipo.",a:true,e:"Esta verificación es un paso explícito antes de la puesta en marcha posterior al mantenimiento."},
{id:"bl011",u:3,t:"Bloqueo",q:"Un buen protocolo de detención de equipo debe indicar cómo y dónde apagar el equipo, y cómo aislar los distintos tipos de energía.",a:true,e:"Estos elementos son parte esencial de un buen protocolo de detención descrito en el documento."},
{id:"bl012",u:3,t:"Bloqueo",q:"Los acumuladores eléctricos, al igual que los hidráulicos, deben bloquearse o desconectarse del sistema antes de intervenir el equipo.",a:true,e:"El documento indica que los acumuladores eléctricos también deben bloquearse o desconectarse, de forma análoga a los hidráulicos."},
// ============ REFUERZO DE BALANCE V/F ============
{id:"bal001",u:1,t:"Fundamentos",q:"Las funciones de un sistema hidráulico se limitan a transmitir fuerza, sin trasladar movimientos ni transformar energía.",a:false,e:"El documento describe tres funciones: transmitir fuerza, trasladar movimientos y transformar la energía mecánica en hidráulica."},
{id:"bal002",u:1,t:"Aceite",q:"El aceite hidráulico solo cumple funciones mecánicas, nunca interviene en la protección química de los componentes.",a:false,e:"Una de sus cinco funciones es precisamente proteger contra la corrosión y ser inocuo con los materiales del sistema."},
{id:"bal003",u:1,t:"Depósito",q:"La principal función del depósito hidráulico es únicamente almacenar el mayor volumen de aceite posible, sin relación con la temperatura.",a:false,e:"Su función principal es dar tiempo para disipar calor, decantar sedimentos y segregar aire, no solo almacenar volumen."},
{id:"bal004",u:1,t:"Bombas",q:"Todas las bombas oleohidráulicas descritas en el documento son de caudal fijo exclusivamente.",a:false,e:"Existen bombas de caudal fijo y de caudal variable, como las de paletas y pistones de placa inclinada."},
{id:"bal005",u:1,t:"Bombas",q:"Las bombas de pistones se utilizan frecuentemente en sistemas hidráulicos de detección de carga y presión compensada.",a:true,e:"El documento indica textualmente esta aplicación típica de las bombas de pistones."},
{id:"bal006",u:1,t:"Bombas",q:"En la mayoría de las bombas de engranajes, el orificio de entrada tiene un diámetro menor que el de salida.",a:false,e:"Es al revés: en la mayoría de las bombas de engranajes el diámetro del orificio de entrada es MAYOR que el de salida."},
{id:"bal007",u:1,t:"Válvulas",q:"Las válvulas de bloqueo o retención solo pueden clasificarse como válvulas de control de presión, ninguna otra categoría.",a:false,e:"Una válvula de retención puede clasificarse como válvula de control de flujo o de control de dirección, no de presión."},
{id:"bal008",u:1,t:"Válvulas",q:"Todas las válvulas de control direccional tienen exactamente el mismo número de posiciones y conexiones.",a:false,e:"El número de posiciones y conexiones varía según el diseño; existen válvulas 4/3, 4/2, 3/2, 5/2, 6/4, entre otras."},
{id:"bal009",u:1,t:"Actuadores",q:"Los actuadores lineales y rotatorios cumplen la misma función: convertir energía oleohidráulica en energía mecánica.",a:true,e:"Ambos tipos de actuadores (cilindros y motores) transforman la energía hidráulica en mecánica, aunque de forma lineal o rotatoria."},
{id:"bal010",u:1,t:"Acumuladores",q:"El acumulador cargado con gas es el único tipo de acumulador oleohidráulico que existe según el documento.",a:false,e:"Existen tres tipos básicos: contrapesado, de resorte y cargado con gas."},
{id:"bal011",u:1,t:"Filtros",q:"Un sistema hidráulico solo puede tener un filtro instalado en toda su configuración, nunca más de uno.",a:false,e:"Un sistema hidráulico puede requerir varios filtros con distintos propósitos: de retorno, de llenado y ventilación, de aspiración, de alta presión, entre otros."},
{id:"bal012",u:1,t:"Simbología",q:"El símbolo ISO de un cilindro de doble efecto y el de un cilindro de simple efecto son visualmente idénticos, sin diferencias.",a:false,e:"Se diferencian: el de simple efecto muestra una lumbrera única con la otra abierta, mientras el de doble efecto muestra dos lumbreras cerradas."},
{id:"bal013",u:1,t:"Simbología",q:"Los símbolos ISO para mandos de válvulas incluyen representaciones distintas para pilotaje, solenoide y control manual.",a:true,e:"El documento muestra símbolos diferenciados para pilotaje externo/interno, solenoide, palanca, pedal, entre otros mandos."},
{id:"bal014",u:1,t:"Circuitos",q:"El montaje de circuitos neumáticos no requiere revisar ningún plano, basta con la experiencia del técnico.",a:false,e:"El documento insiste en que revisar cuidadosamente el plano neumático del equipo es necesario para el montaje correcto."},
{id:"bal015",u:1,t:"Bombas",q:"La bomba de paletas equilibrada hidrostáticamente tiene entre sus componentes principales el rotor, el anillo excéntrico y las paletas.",a:true,e:"Estos son parte de los 7 componentes descritos en el despiece de la bomba de paletas equilibrada."},
{id:"bal016",u:1,t:"Depósito","q":"Los sistemas hidráulicos utilizan exclusivamente un tipo de tanque, sin variantes ventiladas o presurizadas.",a:false,e:"El documento indica que existen dos tipos de tanques: ventilados y presurizados."},
{id:"bal017",u:1,t:"Válvulas",q:"La válvula de alivio de presión y la válvula reductora de presión tienen exactamente el mismo símbolo ISO sin ninguna diferencia.",a:false,e:"Son similares pero se diferencian: la reductora normalmente está abierta y el pilotaje detecta la presión posterior a la válvula, a diferencia de la de alivio."},
{id:"bal018",u:1,t:"Actuadores",q:"El objetivo principal de los actuadores en maquinaria pesada es impulsar implementos como hojas topadoras, baldes y cucharones.",a:true,e:"Esta es la finalidad descrita para los actuadores oleohidráulicos en maquinaria."},
{id:"bal019",u:1,t:"Bombas",q:"Las bombas de paletas de larga duración descritas en el documento presentan un funcionamiento con vibraciones altas y ruido excesivo.",a:false,e:"El documento las describe como de larga duración y funcionamiento suave, no de vibraciones altas o ruido excesivo."},
{id:"bal020",u:1,t:"Simbología",q:"En un plano hidráulico esquemático, los componentes se representan con símbolos geométricos simples en vez de dibujos detallados en corte.",a:true,e:"Esta es la diferencia principal frente al plano cutaway, que sí muestra la construcción interna detallada."},
{id:"bal021",u:3,t:"Seguridad",q:"Los elementos de protección personal son opcionales y quedan a criterio del mantenedor según su comodidad.",a:false,e:"El documento indica que siempre se deben utilizar los EPP requeridos para el proceso de mantenimiento, no son opcionales."},
{id:"bal022",u:3,t:"Seguridad",q:"Los riesgos personales incluyen enfermedades profesionales y accidentes que dañan la integridad física o mental del trabajador.",a:true,e:"Esta es la definición de riesgos personales entregada en el documento."},
{id:"bal023",u:3,t:"Ambiental",q:"Minimizar residuos por mantenimiento y fomentar el reciclaje de componentes son medidas para reducir riesgos medioambientales.",a:true,e:"Ambas son parte de la lista de medidas para reducir los riesgos medioambientales del documento."},
{id:"bal024",u:3,t:"Ambiental",q:"Quemar directamente el aceite hidráulico usado en motores no genera ningún problema ambiental según el documento.",a:false,e:"El documento indica que los gases producidos por la quema directa de aceite usado son altamente nocivos para el medio ambiente."},
{id:"bal025",u:3,t:"Cambio de aceite",q:"El aceite HYDO Cat y el aceite multiuso para tractores son ejemplos de aceites hidráulicos aprobados por Caterpillar.",a:true,e:"Ambos aparecen listados como aceites hidráulicos Caterpillar aprobados en el documento."},
{id:"bal026",u:3,t:"Bloqueo",q:"El bloqueo con cables se utiliza, entre otros usos, para impedir que se modifique la presión de trabajo definida en válvulas de presión.",a:true,e:"Esta es una de las aplicaciones descritas para el bloqueo con cables en válvulas de mando."},
{id:"bal027",u:3,t:"Bloqueo",q:"Las tarjetas y etiquetas de bloqueo no cumplen ninguna función si el equipo ya tiene un candado instalado.",a:false,e:"Las tarjetas y etiquetas se usan justamente para rotular claramente que el equipo está en mantenimiento, complementando al candado, no reemplazándolo ni siendo redundantes."},
{id:"bal028",u:3,t:"Mantenimiento",q:"El kilometraje de operación puede ser un criterio válido, junto con las horas de trabajo, para programar mantenimientos preventivos.",a:true,e:"El documento indica que los mantenimientos programados se realizan según horas de trabajo o, en otros casos, según kilometraje."},
{id:"bal029",u:3,t:"Verificación",q:"Las inspecciones periódicas del sistema hidráulico pueden ser realizadas tanto por el operador como por personal de mantenimiento.",a:true,e:"El documento indica que ambos perfiles pueden realizar estas inspecciones o verificaciones periódicas."},
{id:"bal030",u:3,t:"Seguridad",q:"Según el documento, no existe ninguna relación entre el acoplamiento inadecuado de componentes de alta y baja presión y el riesgo de rotura.",a:false,e:"El documento advierte que acoplar de forma inapropiada componentes de alta y baja presión aumenta la probabilidad de rupturas de mangueras o fittings."},
{id:"bal031",u:1,t:"Válvulas",q:"Las válvulas de alivio de presión también son conocidas como válvulas de seguridad o válvulas relief.",a:true,e:"El documento menciona estos nombres alternativos para las válvulas de alivio/limitadoras de presión."},
{id:"bal032",u:1,t:"Bombas",q:"Las bombas de engranajes son consideradas de diseño complejo y de construcción delicada, poco usadas en maquinaria pesada.",a:false,e:"Al contrario, son de diseño simple y construcción robusta, ampliamente usadas en dirección, frenos, levante y accesorios."},
{id:"bal033",u:3,t:"Seguridad",q:"El uso de rótulos y candados de bloqueo busca impedir que la maquinaria sea encendida o maniobrada durante el mantenimiento.",a:true,e:"Esta es la finalidad principal de aplicar rótulos y elementos de bloqueo antes de intervenir el equipo."},
{id:"bal034",u:1,t:"Simbología",q:"Un motor de combustión interna y un motor eléctrico como fuentes externas de energía comparten exactamente el mismo símbolo ISO.",a:false,e:"El documento muestra símbolos distintos para el motor de combustión interna y el motor eléctrico como fuentes externas de energía."},
{id:"bal035",u:1,t:"Depósito",q:"La presión interna de un depósito presurizado ayuda a evitar la cavitación de la bomba.",a:true,e:"Esta es una de las ventajas del depósito presurizado descritas en el documento."},
];
